const __ML_GRID = "";

function classifyStar(t, mv) {
  let k_idx = Math.round((t - 3000) / 50);
  let mv_idx = Math.round((mv - -15) / 0.1);

  // Clamp
  if (k_idx < 0) k_idx = 0; if (k_idx > 740) k_idx = 740;
  if (mv_idx < 0) mv_idx = 0; if (mv_idx > 300) mv_idx = 300;

  const flat_idx = k_idx * 301 + mv_idx;
  const c = __ML_GRID.charAt(flat_idx);

  if (c === 'g') return '거성';
  if (c === 'w') return '백색왜성';
  return '주계열성';
}
function getStarTrain() { return STAR_TRAIN_IDX.filter(i => i < STAR_DATA.length).map(i => STAR_DATA[i]); }
function getStarTest() { return STAR_TEST_IDX.filter(i => i < STAR_DATA.length).map(i => STAR_DATA[i]); }

